package workloadmanager

import (
	"sync"
	"time"
)

// TokenCache caches authentication tokens
type TokenCache struct {
	cache     map[string]tokenEntry
	maxSize   int
	ttl       time.Duration
	mu        sync.RWMutex
}

type tokenEntry struct {
	token     string
	expiresAt time.Time
}

// NewTokenCache creates a new token cache
func NewTokenCache(maxSize int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		cache:   make(map[string]tokenEntry),
		maxSize: maxSize,
		ttl:     ttl,
	}
}

// Get retrieves a token from the cache
func (c *TokenCache) Get(key string) (string, bool) {
	c.mu.RLock()
	entry, exists := c.cache[key]
	c.mu.RUnlock()

	if !exists {
		return "", false
	}

	if time.Now().After(entry.expiresAt) {
		c.mu.Lock()
		delete(c.cache, key)
		c.mu.Unlock()
		return "", false
	}

	return entry.token, true
}

// Set stores a token in the cache
func (c *TokenCache) Set(key, token string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Simple eviction: clear if at capacity
	if len(c.cache) >= c.maxSize {
		c.cache = make(map[string]tokenEntry)
	}

	c.cache[key] = tokenEntry{
		token:     token,
		expiresAt: time.Now().Add(c.ttl),
	}
}

// Delete removes a token from the cache
func (c *TokenCache) Delete(key string) {
	c.mu.Lock()
	delete(c.cache, key)
	c.mu.Unlock()
}

