// Informers manages Kubernetes informers for watching resources
type Informers struct {
	factory    informers.SharedInformerFactory
	synced     []cache.InformerSynced
}

// NewInformers creates new informers for the workload manager
func NewInformers(config *rest.Config) (*Informers, error) {
	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create kubernetes client: %w", err)
	}

	factory := informers.NewSharedInformerFactory(clientset, 10*time.Minute)

	// Add pod informer
	podInformer := factory.Core().V1().Pods().Informer()

	return &Informers{
		factory: factory,
		synced:  []cache.InformerSynced{podInformer.HasSynced},
	}, nil
}

// WaitForSync waits for all informers to sync
func (i *Informers) WaitForSync(ctx context.Context) error {
	if len(i.synced) == 0 {
		return nil
	}

	// Wait for all informers to sync
	if !cache.WaitForCacheSync(ctx.Done(), i.synced...) {
		return fmt.Errorf("failed to sync informers")
	}

	return nil
}

