)

func TestNewTokenCache(t *testing.T) {
	cache := NewTokenCache(100, 5*time.Minute)
	assert.NotNil(t, cache)
	assert.Equal(t, 100, cache.maxSize)
	assert.Equal(t, 5*time.Minute, cache.ttl)
}

func TestTokenCacheGetSet(t *testing.T) {
	cache := NewTokenCache(100, 5*time.Minute)

	// Test Set and Get
	cache.Set("key1", "token1")
	token, found := cache.Get("key1")
	assert.True(t, found)
	assert.Equal(t, "token1", token)

	// Test Get non-existent key
	token, found = cache.Get("nonexistent")
	assert.False(t, found)
	assert.Empty(t, token)
}

func TestTokenCacheExpiration(t *testing.T) {
	// Create cache with very short TTL
	cache := NewTokenCache(100, 1*time.Millisecond)

	cache.Set("key1", "token1")

	// Should exist immediately
	token, found := cache.Get("key1")
	assert.True(t, found)
	assert.Equal(t, "token1", token)

	// Wait for expiration
	time.Sleep(10 * time.Millisecond)

	// Should be expired now
	token, found = cache.Get("key1")
	assert.False(t, found)
	assert.Empty(t, token)
}

func TestTokenCacheDelete(t *testing.T) {
	cache := NewTokenCache(100, 5*time.Minute)

	cache.Set("key1", "token1")
	token, found := cache.Get("key1")
	assert.True(t, found)
	assert.Equal(t, "token1", token)

	cache.Delete("key1")
	token, found = cache.Get("key1")
	assert.False(t, found)
	assert.Empty(t, token)
}

func TestTokenCacheEviction(t *testing.T) {
	// Create cache with small size
	cache := NewTokenCache(2, 5*time.Minute)

	cache.Set("key1", "token1")
	cache.Set("key2", "token2")

	// Both should exist
	_, found := cache.Get("key1")
	assert.True(t, found)
	_, found = cache.Get("key2")
	assert.True(t, found)

	// Add third entry, should trigger eviction
	cache.Set("key3", "token3")

	// Cache should be cleared (simple eviction strategy)
	// Note: In a real implementation, you might want LRU eviction
}

